function rewriteBundle(regex, replaceFn) {
  return {
    name: 'rewrite-bundle',
    generateBundle(options, bundle) {
      for (const fileName of Object.keys(bundle)) {
        const chunk = bundle[fileName];
        const updatedCode = chunk.code.replace(regex, replaceFn);
        chunk.code = updatedCode;
      }
    }
  };
}

private getCatalogLocales(): CatalogLocales {
  if (this.catalogLocales) {
    return this.catalogLocales;
  } else {
    const messagesDir = path.join(this.projectRoot, this.config.extract.path);
    this.catalogLocales = new CatalogLocales({
      messagesDir,
      extension: getFormatExtension(this.config.messages.format),
      locales: this.config.extract.locales,
      sourceLocale: this.config.extract.sourceLocale
    });
    return this.catalogLocales;
  }
}

private async loadSourceMessages(): Promise<Map<string, ExtractorMessage>> {
  // Load source catalog to hydrate metadata (e.g. flags) later without
  // treating catalog entries as source of truth.
  const diskMessages = await this.loadLocaleMessages(
    this.config.extract.sourceLocale
  );
  const byId = new Map<string, ExtractorMessage>();
  for (const diskMessage of diskMessages) {
    byId.set(diskMessage.id, diskMessage);
  }
  return byId;
}

public static shouldEnterDirectory(
  dirPath: string,
  srcPaths: Array<string>
): boolean {
  const dirName = path.basename(dirPath);
  if (SourceFileFilter.IGNORED_DIRECTORIES.includes(dirName)) {
    return SourceFileFilter.isIgnoredDirectoryExplicitlyIncluded(
      dirPath,
      srcPaths
    );
  }
  return true;
}

export function normalizePathToPosix(filePath: string): string {
  // `path.relative` uses OS-specific separators. For stable `.po` references we
  // always use POSIX separators, regardless of the OS that ran extraction.
  return path.posix.normalize(
    filePath.split(path.win32.sep).join(path.posix.sep)
  );
}

function warnAboutMissingReference(
  id: string,
  warnedMissingReferenceIds: Set<string>
): void {
  if (warnedMissingReferenceIds.has(id)) return;
  warnedMissingReferenceIds.add(id);
  warn(`Missing file reference for extracted message: ${id}`);
}

export function getMessagesFromConfig(
  config: Awaited<ReturnType<typeof getConfig>>
): ReturnType<typeof useMessagesType> {
  if (!config.messages) {
    throw new Error(
      'No messages found. Have you configured them correctly? See https://next-intl.dev/docs/configuration#messages'
    );
  }
  return config.messages;
}

export default function validateLocale(locale: string) {
  try {
    const constructed = new Intl.Locale(locale);
    if (!constructed.language) {
      throw new Error('Language is required');
    }
  } catch {
    console.error(
      `An invalid locale was provided: "${locale}"\nPlease ensure you're using a valid Unicode locale identifier (e.g. "en-US").`
    );
  }
}

export function getLocalizedTemplate<AppLocales extends Locales>(
  pathnameConfig: Pathnames<AppLocales>[keyof Pathnames<AppLocales>],
  locale: AppLocales[number],
  internalTemplate: string
) {
  return typeof pathnameConfig === 'string'
    ? pathnameConfig
    : pathnameConfig[locale] || internalTemplate;
}

function calculateRelativeTimeValue(
  seconds: number,
  unit: Intl.RelativeTimeFormatUnit
) {
  // We have to round the resulting values, as `Intl.RelativeTimeFormat`
  // will include fractions like '2.1 hours ago'.
  return Math.round(seconds / UNIT_SECONDS[unit]);
}

constructor(code: IntlErrorCode, originalMessage?: string) {
  let message: string = code;
  if (originalMessage) {
    message += ': ' + originalMessage;
  }
  super(message);

  this.code = code;
  if (originalMessage) {
    this.originalMessage = originalMessage;
  }
}

export async function updateRecord(
  db: D1Database,
  SQL: string,
  bindings: any[]
) {
  try {
    bindings = cleanBindings(bindings)
    return await db
      .prepare(SQL)
      .bind(...bindings)
      .run()
  } catch (e: any) {
    console.error(e.message, e.cause?.message)
    throw e
  }
}

export function DrizzleAdapter<SqlFlavor extends SqlFlavorOptions>(
  db: SqlFlavor,
  schema?: DefaultSchema<SqlFlavor>
): Adapter {
  if (is(db, MySqlDatabase)) {
    return MySqlDrizzleAdapter(db, schema as DefaultMySqlSchema)
  } else if (is(db, PgDatabase)) {
    return PostgresDrizzleAdapter(db, schema as DefaultPostgresSchema)
  } else if (is(db, BaseSQLiteDatabase)) {
    return SQLiteDrizzleAdapter(db, schema as DefaultSQLiteSchema)
  }

  throw new Error(
    `Unsupported database type (${typeof db}) in Auth.js Drizzle adapter.`
  )
}

async create(options: InternalOptions<"oauth">) {
  const code_verifier = o.generateRandomCodeVerifier()
  const value = await o.calculatePKCECodeChallenge(code_verifier)
  const cookie = await sealCookie("pkceCodeVerifier", code_verifier, options)
  return { cookie, value }
}

constructor(
  option: CookieOption,
  cookies: RequestInternal["cookies"],
  logger: LoggerInstance | Console
) {
  this.#logger = logger
  this.#option = option
  if (!cookies) return

  const { name: sessionCookiePrefix } = option

  for (const [name, value] of Object.entries(cookies)) {
    if (!name.startsWith(sessionCookiePrefix) || !value) continue
    this.#chunks[name] = value
  }
}

export function assertInternalOptionsWebAuthn(
  options: InternalOptions
): InternalOptionsWebAuthn {
  const { provider, adapter } = options

  // Adapter is required for WebAuthn
  if (!adapter)
    throw new MissingAdapter("An adapter is required for the WebAuthn provider")
  // Provider must be WebAuthn
  if (!provider || provider.type !== "webauthn") {
    throw new InvalidProvider("Provider must be WebAuthn")
  }
  // Narrow the options type for typed usage later
  return { ...options, provider, adapter }
}

function isEditableTarget(target: EventTarget | null) {
  return (
    (target instanceof HTMLElement && target.isContentEditable) ||
    target instanceof HTMLInputElement ||
    target instanceof HTMLTextAreaElement ||
    target instanceof HTMLSelectElement
  )
}

function normalizeFontHeading(
  font: FontValue,
  fontHeading: FontHeadingValue
): FontHeadingValue {
  // Persist "same as body" as an explicit inherit sentinel so the body font
  // can change later without freezing headings to a concrete previous value.
  return fontHeading === font ? "inherit" : fontHeading
}

async (name: string, styleName: Style["name"]) => {
  // Try registry item first, then fallback to demo item (for examples).
  const item = await getRegistryItem(name, styleName)
  if (item) {
    return item
  }
  return await getDemoItem(name, styleName)
}

async function printDiff(diff: Change[]) {
  diff.forEach((part) => {
    if (part) {
      if (part.added) {
        return process.stdout.write(highlighter.success(part.value))
      }
      if (part.removed) {
        return process.stdout.write(highlighter.error(part.value))
      }

      return process.stdout.write(part.value)
    }
  })
}

export function printPresetDecode(result: PresetDecodeResult) {
  printPresetInfo(
    {
      code: result.code,
      fallbacks: result.derived,
      values: result.values,
    },
    {
      fallbackNote: "  * Compatibility value for older preset versions.",
    }
  )
}

function parseFontFromDependency(value: string | undefined) {
  if (!value) {
    return null
  }

  const normalized = normalizeCssValue(value)
  // Preset font imports use variable fontsource packages.
  const prefix = "@fontsource-variable/"
  if (!normalized.startsWith(prefix)) {
    return null
  }

  return toPresetFont(normalized.slice(prefix.length))
}

export async function getRegistriesIndex(options?: { useCache?: boolean }) {
  // Fetch new format and transform to old Record<string, string> for backward compatibility.
  const registries = await getRegistries(options)
  if (!registries) return null
  return Object.fromEntries(registries.map((r) => [r.name, r.url])) as z.infer<
    typeof registriesIndexSchema
  >
}

constructor(
  public readonly url: string,
  cause?: unknown
) {
  const message = `The item at ${url} was not found. It may not exist at the registry.`

  super(message, {
    code: RegistryErrorCode.NOT_FOUND,
    statusCode: 404,
    cause,
    context: { url },
    suggestion:
      "Check if the item name is correct and the registry URL is accessible.",
  })
  this.name = "RegistryNotFoundError"
}

export function getRegistryItemFileSource(
  itemName: string,
  filePath: string,
  itemSources: Map<string, RegistryItemSource>,
  fallbackDir: string
) {
  const source = itemSources.get(itemName)
  return path.resolve(source?.registryDir ?? fallbackDir, filePath)
}

export function getRegistryItemFileRootPath(
  itemName: string,
  filePath: string,
  itemSources: Map<string, RegistryItemSource>,
  rootDir: string,
  fallbackDir: string
) {
  const sourcePath = getRegistryItemFileSource(
    itemName,
    filePath,
    itemSources,
    fallbackDir
  )

  return path.relative(rootDir, sourcePath).split(path.sep).join("/")
}

async function readRegistryJson(registryFile: string) {
  try {
    return await fs.readFile(registryFile, "utf-8")
  } catch (error) {
    throw new RegistryLocalFileError(registryFile, error, {
      message: `Failed to read registry file at ${registryFile}.`,
      context: { registryFile },
      suggestion:
        "Check that the registry.json file exists and that the path is correct.",
    })
  }
}

export async function loadRegistryItem(
  itemName: string,
  options?: LoadRegistryOptions
) {
  const { cwd, registryFile } = resolveLoadRegistryOptions(options)
  const result = await readRegistryWithIncludes(registryFile, { cwd })
  const item = result.registry.items.find((item) => item.name === itemName)

  if (!item) {
    throw new RegistryItemNotFoundError(itemName)
  }

  const rootDir = getRegistryRootDir(result, cwd, registryFile)

  return createRegistryItem(item, result, rootDir, cwd)
}

function createRegistryCatalogFromSource(result: SourceRegistryLoadResult) {
  return {
    ...result.registry,
    items: result.registry.items.map((item) =>
      stripRegistryItemFileContent(
        rewriteRegistryItemFilePaths(item, result.itemSourcesByItem)
      )
    ),
  }
}

export async function loadRegistryCatalogFromSource(
  reader: RegistrySourceReader,
  options: {
    registryFile?: string
    source?: string
  } = {}
) {
  const registryFile = normalizeSourcePath(
    options.registryFile ?? "registry.json"
  )
  const result = await readSourceRegistryWithIncludes(registryFile, reader, {
    source: options.source,
  })

  return createRegistryCatalogFromSource(result)
}
